using System; using System.Linq; using System.Windows; using System.Windows.Controls; using WarehouseManagement.ApplicationData;
namespace WarehouseManagement.Pages { public partial class ProductCardPage:Page { Products product; public ProductCardPage(Products p){InitializeComponent(); product=p; cmbCategory.ItemsSource=AppConnect.model01.Categories.ToList(); cmbCategory.DisplayMemberPath="CategoryName"; cmbBrand.ItemsSource=AppConnect.model01.Suppliers.ToList(); cmbBrand.DisplayMemberPath="SupplierName"; cmbStatus.ItemsSource=AppConnect.model01.Units.ToList(); cmbStatus.DisplayMemberPath="ShortName"; if(p!=null){tbTitle.Text="Редактирование товара"; txtName.Text=p.ProductName; txtDescription.Text=p.Description; txtPrice.Text=p.SalePrice.ToString(); txtQuantity.Text=p.MinStock.ToString(); cmbCategory.SelectedItem=cmbCategory.Items.Cast<Categories>().FirstOrDefault(x=>x.CategoryID==p.CategoryID); cmbBrand.SelectedItem=cmbBrand.Items.Cast<Suppliers>().FirstOrDefault(x=>x.SupplierID==p.SupplierID); cmbStatus.SelectedItem=cmbStatus.Items.Cast<Units>().FirstOrDefault(x=>x.UnitID==p.UnitID);}} private void btnBack_Click(object s,RoutedEventArgs e){AppFrame.frmMain.GoBack();} private void btnSave_Click(object s,RoutedEventArgs e){decimal price; int min; if(!decimal.TryParse(txtPrice.Text,out price)||!int.TryParse(txtQuantity.Text,out min)||cmbCategory.SelectedItem==null||cmbBrand.SelectedItem==null||cmbStatus.SelectedItem==null||string.IsNullOrWhiteSpace(txtName.Text)){MessageBox.Show("Проверьте корректность полей");return;} if(product==null){product=new Products{Sku="SKU-"+DateTime.Now.Ticks.ToString().Substring(10), IsActive=true, PurchasePrice=price, StockBalances=null}; AppConnect.model01.Products.Add(product);} product.ProductName=txtName.Text.Trim(); product.Description=txtDescription.Text.Trim(); product.SalePrice=price; product.MinStock=min; product.CategoryID=((Categories)cmbCategory.SelectedItem).CategoryID; product.SupplierID=((Suppliers)cmbBrand.SelectedItem).SupplierID; product.UnitID=((Units)cmbStatus.SelectedItem).UnitID; AppConnect.model01.SaveChanges(); WarehouseService.Log("Изменение","Products",product.ProductID,product.ProductName); MessageBox.Show("Товар сохранён"); AppFrame.frmMain.GoBack();} private void btnAddCategory_Click(object s,RoutedEventArgs e){MessageBox.Show("Категории добавляются SQL-скриптом или администратором БД");} private void btnAddBrand_Click(object s,RoutedEventArgs e){MessageBox.Show("Поставщики ведутся в разделе поставщиков");} }}
